#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int S, SG, FG, D, T;
        scanf("%d %d %d %d %d", &S, &SG, &FG, &D, &T);
        double distance = (D - 1) * 50.0 / 1000.0;
        double otherCarSpeed = (distance / (T / 3600.0)) + S;
        if (abs(otherCarSpeed - SG) < abs(otherCarSpeed - FG)) {
            printf("SEBI\n");
        } else if (abs(otherCarSpeed - SG) > abs(otherCarSpeed - FG)) {
            printf("FATHER\n");
        } else {
            printf("DRAW\n");
        }
    }
    return 0;
}

